import{_ as a,o as t,c as i,ag as s}from"./chunks/framework.CHQlKclR.js";const u=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),o={name:"guide/getting-started.md"};function n(r,e,l,p,d,h){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>Before utilizing the massive power of Vortex, ensure your environment is fully prepared!</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Verified Stack</p><ul><li><strong>PROS 4.x</strong> or higher installed.</li><li><strong>A VEX V5 Brain</strong> and firmware up to date.</li><li><strong>VS Code</strong> with the PROS V5 extension optimally configured.</li></ul></div><h2 id="_1-quick-install-via-depot" tabindex="-1">1. Quick Install via Depot <a class="header-anchor" href="#_1-quick-install-via-depot" aria-label="Permalink to &quot;1. Quick Install via Depot&quot;">​</a></h2><p>Vortex is maintained securely via our high-speed depot. From the root of your project terminal, execute the following commands:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pros</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add-depot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Vortex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/VortexLib/Vortex/depot/stable.json</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pros</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Vortex</span></span></code></pre></div><blockquote><p><strong>Note</strong>: <code>add-depot</code> only needs to be run once per machine! You can continue using <code>pros c install Vortex</code> on future projects smoothly!</p></blockquote><h2 id="_2-upgrading" tabindex="-1">2. Upgrading <a class="header-anchor" href="#_2-upgrading" aria-label="Permalink to &quot;2. Upgrading&quot;">​</a></h2><p>To pull in the newest algorithms and bug fixes on a previous install:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pros</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Vortex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --upgrade</span></span></code></pre></div><h2 id="_3-verify-the-installation" tabindex="-1">3. Verify the Installation! <a class="header-anchor" href="#_3-verify-the-installation" aria-label="Permalink to &quot;3. Verify the Installation!&quot;">​</a></h2><p>Simply pop open your <code>main.h</code> (or <code>main.cpp</code>) and verify the library linker completes:</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#include</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Vortex/api.hpp&quot;</span></span></code></pre></div><p>Compile with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span></span></code></pre></div><p>If it successfully links and throws no compilation errors, you are completely armed and ready to conquer the field! 🎉</p><h2 id="choosing-your-starting-point" tabindex="-1">Choosing Your Starting Point <a class="header-anchor" href="#choosing-your-starting-point" aria-label="Permalink to &quot;Choosing Your Starting Point&quot;">​</a></h2><p>Vortex offers two ways to jump into development:</p><h3 id="a-blank-template-recommended-for-veterans" tabindex="-1">A. Blank Template (Recommended for Veterans) <a class="header-anchor" href="#a-blank-template-recommended-for-veterans" aria-label="Permalink to &quot;A. Blank Template (Recommended for Veterans)&quot;">​</a></h3><p>If you already have a codebase or want to start from scratch, simply install the library as shown above and start including <code>Vortex/api.hpp</code>.</p><h3 id="b-example-project-recommended-for-starters" tabindex="-1">B. Example Project (Recommended for Starters) <a class="header-anchor" href="#b-example-project-recommended-for-starters" aria-label="Permalink to &quot;B. Example Project (Recommended for Starters)&quot;">​</a></h3><p>We provide a pre-configured <strong>Example Project</strong> that includes:</p><ul><li>A fully mapped Chassis with PID constants.</li><li>Example Autonomous routines (Swing, Drive, Turn).</li><li>A subsystem structure ready for expansion.</li></ul><p>You can download the latest <code>Vortex-Example-Project.zip</code> from our <a href="https://github.com/jonahchang207/Vortex/releases" target="_blank" rel="noreferrer">GitHub Releases</a>. Unzip it and open the folder in VS Code to get started immediately!</p>`,25)])])}const g=a(o,[["render",n]]);export{u as __pageData,g as default};
